let data = msg.payload.data || msg.payload;
if (!data || !data.keypoints || !data.keypoints[0] || !data.keypoints[0][1]) return null;

const kpts = data.keypoints[0][1];

// YOLOv11 pose keypoint index definitions
const LEFT_SHOULDER = 5;
const RIGHT_SHOULDER = 6;
const LEFT_WRIST = 9;
const RIGHT_WRIST = 10;

// Helper function to extract keypoints
function getPt(i) {
    const p = kpts[i];
    if (!p || p[0] <= 1) return null;
    return { x: p[0], y: p[1], conf: p[2] || 0 };
}

const ls = getPt(LEFT_SHOULDER);
const rs = getPt(RIGHT_SHOULDER);
const lw = getPt(LEFT_WRIST);
const rw = getPt(RIGHT_WRIST);

// Check if keypoints exist and confidence > 0.4 to avoid false positives
if (!ls || !rs || !lw || !rw || ls.conf < 0.4 || rs.conf < 0.4 || lw.conf < 0.4 || rw.conf < 0.4) {
    return null;
}

// Calculate straight-line distance between shoulders and between wrists
const distShoulders = Math.sqrt(Math.pow(ls.x - rs.x, 2) + Math.pow(ls.y - rs.y, 2));
const distWrists = Math.sqrt(Math.pow(lw.x - rw.x, 2) + Math.pow(lw.y - rw.y, 2));

// Core logic: if wrist distance is less than shoulder distance, action is triggered
const isTriggered = distWrists < distShoulders;

// Get last trigger time, set a 10-second cooldown to avoid repeated triggering during recording and playback
let lastTriggerTime = context.get("lastTriggerTime") || 0;
const currentTime = Date.now();

if (isTriggered && (currentTime - lastTriggerTime > 10000)) {
    context.set("lastTriggerTime", currentTime);
    return { payload: "Trigger recording!" };
}

return null;

let buf = msg.payload;
if (buf && buf.length > 44 && buf.slice(0, 4).toString() === 'RIFF') {
    msg.payload = buf.slice(44);
} else {
    msg.payload = buf;
}
node.status({ fill: 'blue', shape: 'dot', text: 'PCM ' + msg.payload.length + 'B' });
return msg;

// ===== iFlytek STT: PCM → text =====

const APPID = "da94379a";
const APISecret = "NGRlZDk2MDY0ODA1NTViNGVhNTY2YmFm";
const APIKey = "e23e27197669ca24bcc1f76574007dbe";

function getAuthUrl(host, path) {
    const date = new Date().toUTCString();
    const signatureOrigin = "host: " + host + "\ndate: " + date + "\nGET " + path + " HTTP/1.1";
    const signature = crypto.createHmac('sha256', APISecret).update(signatureOrigin).digest('base64');
    const authOrigin = "api_key=\"" + APIKey + "\", algorithm=\"hmac-sha256\", headers=\"host date request-line\", signature=\"" + signature + "\"";
    const auth = Buffer.from(authOrigin).toString('base64');
    return "wss://" + host + path + "?authorization=" + encodeURIComponent(auth) + "&date=" + encodeURIComponent(date) + "&host=" + encodeURIComponent(host);
}

const audioData = msg.payload;
const url = getAuthUrl('iat-api.xfyun.cn', '/v2/iat');
const socket = new ws(url);
let resultText = [];
let timeout = setTimeout(function() { try { socket.close(); } catch(e) {} node.error('STT timeout'); }, 15000);

socket.on('open', function() {
    const chunkSize = 8000;
    let offset = 0;
    function sendChunk() {
        if (offset >= audioData.length) return;
        let end = offset + chunkSize;
        let chunk = audioData.slice(offset, end);
        let status;
        if (offset === 0) status = 0;
        else status = 1;
        if (end >= audioData.length) status = 2;
        const frame = {
            common: { app_id: APPID },
            business: { domain: "iat", language: "zh_cn", accent: "mandarin", vinfo: 1, vad_eos: 10000 },
            data: { status: status, format: "audio/L16;rate=16000", audio: chunk.toString('base64'), encoding: "raw" }
        };
        socket.send(JSON.stringify(frame));
        offset = end;
        if (status !== 2) setTimeout(sendChunk, 40);
    }
    sendChunk();
});

socket.on('message', function(data) {
    const m = JSON.parse(data);
    if (m.code !== 0) { node.error("STT Error: " + m.code + " - " + (m.message || 'unknown')); socket.close(); return; }
    const wsData = m.data.result.ws;
    for (const item of wsData) { for (const w of item.cw) { resultText.push(w.w); } }
    if (m.data.status === 2) { socket.close(); }
});

socket.on('close', function() {
    clearTimeout(timeout);
    const text = resultText.join('');
    node.status({ fill: 'green', shape: 'dot', text: "Recognized: " + (text || '(empty)').substring(0, 20) });
    node.send({ payload: text });
});

socket.on('error', function(e) { clearTimeout(timeout); node.error("STT WS Error: " + e.message); });

