const APPID = "da94379a";
const APISecret = "NGRlZDk2MDY0ODA1NTViNGVhNTY2YmFm";
const APIKey = "e23e27197669ca24bcc1f76574007dbe";
const OUT_FILE = "/tmp/reply.wav";
const SCRIPT_PATH = "/tmp/_tts_runner.js";

const host = "cbm01.cn-huabei-1.xf-yun.com";
const apiPath = "/v1/private/mcd9m97e6";
const date = new Date().toUTCString();
const sigOrigin = "host: " + host + "\ndate: " + date + "\nGET " + apiPath + " HTTP/1.1";
const sig = crypto.createHmac('sha256', APISecret).update(sigOrigin).digest('base64');
const authO = "api_key=\"" + APIKey + "\", algorithm=\"hmac-sha256\", headers=\"host date request-line\", signature=\"" + sig + "\"";
const authB64 = Buffer.from(authO).toString('base64');
const ttsUrl = "wss://" + host + apiPath + "?authorization=" + encodeURIComponent(authB64) + "&date=" + encodeURIComponent(date) + "&host=" + encodeURIComponent(host);

const text = msg.payload || "";
if (!String(text).trim()) { node.error('TTS input is empty'); return; }
node.warn('Requesting TTS synthesis: ' + text);

// Build independent script v4
const script = [
    "const fs = require('fs');",
    "try {",
    "  let WebSocket = null;",
    "  const wsPaths = ['ws', '/usr/lib/node_modules/ws', '/usr/local/lib/node_modules/ws',",
    "    (process.env.HOME || '/root') + '/.node-red/node_modules/ws',",
    "    '/usr/lib/node-red/node_modules/ws', '/opt/node_modules/ws'];",
    "  for (const p of wsPaths) { try { WebSocket = require(p); break; } catch(e) {} }",
    "  if (!WebSocket) { fs.writeFileSync('/tmp/_tts_err', 'Cannot find ws module'); process.exit(1); }",
    "  const url = " + JSON.stringify(ttsUrl) + ";",
    "  const text = " + JSON.stringify(text) + ";",
    "  const appid = " + JSON.stringify(APPID) + ";",
    "  const outFile = " + JSON.stringify(OUT_FILE) + ";",
    "  const chunks = [];",
    "  const sock = new WebSocket(url);",
    "  const timer = setTimeout(function() { try{sock.close();}catch(e){} fs.writeFileSync('/tmp/_tts_err','timeout after 20s'); process.exit(1); }, 20000);",
    "  sock.on('open', function() {",
    "    sock.send(JSON.stringify({",
    "      header: { app_id: appid, status: 2 },",
    "      parameter: { tts: { vcn: 'x5_EnUs_Lila_flow', speed: 50, volume: 50, pitch: 50, audio: { encoding: 'raw', sample_rate: 16000 } } },",
    "      payload: { text: { encoding: 'utf8', status: 2, text: Buffer.from(text).toString('base64') } }",
    "    }));",
    "  });",
    "  sock.on('message', function(d) {",
    "    const m = JSON.parse(d);",
    "    const code = m.header ? m.header.code : -1;",
    "    const status = m.header ? m.header.status : -1;",
    "    if (code !== 0) {",
    "      clearTimeout(timer);",
    "      fs.writeFileSync('/tmp/_tts_err', 'code=' + code + ' ' + (m.header.message || ''));",
    "      process.exit(1);",
    "    }",
    "    // Only middle frames with status=1 have actual audio data",
    "    if (status === 1 && m.payload && m.payload.audio && m.payload.audio.audio) {",
    "      chunks.push(Buffer.from(m.payload.audio.audio, 'base64'));",
    "    }",
    "    if (status === 2) {",
    "      clearTimeout(timer);",
    "      if (chunks.length === 0) {",
    "        fs.writeFileSync('/tmp/_tts_err', 'finished but no audio chunks received');",
    "        process.exit(1);",
    "      }",
    "      const pcm = Buffer.concat(chunks);",
    "      const hdr = Buffer.alloc(44);",
    "      hdr.write('RIFF',0); hdr.writeUInt32LE(36+pcm.length,4); hdr.write('WAVE',8); hdr.write('fmt ',12);",
    "      hdr.writeUInt32LE(16,16); hdr.writeUInt16LE(1,20); hdr.writeUInt16LE(1,22);",
    "      hdr.writeUInt32LE(16000,24); hdr.writeUInt32LE(32000,28);",
    "      hdr.writeUInt16LE(2,32); hdr.writeUInt16LE(16,34);",
    "      hdr.write('data',36); hdr.writeUInt32LE(pcm.length,40);",
    "      fs.writeFileSync(outFile, Buffer.concat([hdr, pcm]));",
    "      sock.close();",
    "    }",
    "  });",
    "  sock.on('error', function(e) { clearTimeout(timer); fs.writeFileSync('/tmp/_tts_err', 'ws-error: ' + e.message); process.exit(1); });",
    "} catch(e) { fs.writeFileSync('/tmp/_tts_err', 'top-err: ' + e.message); process.exit(1); }"
].join("\n");

fs.writeFileSync(SCRIPT_PATH, script);
node.warn('Launching independent Node process...');

try {
    const cmd = "NODE_PATH=$HOME/.node-red/node_modules:/usr/lib/node_modules:/usr/local/lib/node_modules:/usr/lib/node-red/node_modules node " + SCRIPT_PATH;
    cp.execSync(cmd, { timeout: 25000, stdio: 'pipe' });
    let errMsg = '';
    try { errMsg = fs.readFileSync('/tmp/_tts_err', 'utf8'); } catch(e) {}
    if (errMsg) {
        node.status({ fill: 'red', shape: 'ring', text: 'TTS failed' });
        node.send({ payload: { ok: false, error: errMsg, text: text } });
        return;
    }
    const stat = fs.statSync(OUT_FILE);
    node.status({ fill: 'green', shape: 'dot', text: 'TTS success ' + stat.size + 'B' });
    node.warn('WAV saved: ' + OUT_FILE + ' (' + stat.size + ' bytes)');
    node.send({ payload: { ok: true, text: text, size: stat.size, file: OUT_FILE } });
} catch(e) {
    let errMsg = e.message;
    try { errMsg = fs.readFileSync('/tmp/_tts_err', 'utf8'); } catch(e2) {}
    node.status({ fill: 'red', shape: 'ring', text: 'Execution failed' });
    node.error('TTS exec failed: ' + errMsg);
    node.send({ payload: { ok: false, error: errMsg, text: text } });
}
